def mat_pow(Mt, p):
    d = len(Mt)
    res = [[1 if i == j else 0 for j in range(d)] for i in range(d)]
    base = [row[:] for row in Mt]
    while p > 0:
        if p & 1:
            res = mat_mul(res, base)
        base = mat_mul(base, base)
        p >>= 1
    return res

def mat_pow(Mt, p):
    d = len(Mt)
