def mat_pow(Mt, p):
    if p == 0:
        return Mt
    if p % 2 == 0:
        half = mat_pow(Mt, p//2)
        return mat_mul(half, half)
    else:
        return mat_mul(mat_pow(Mt, p-1), Mt)

